package com.example.sharesample; // Replace with your actual package name

import android.app.Activity;
import android.content.Intent;
import android.graphics.Bitmap;
import android.graphics.BitmapFactory;
import android.net.Uri;
import android.os.Bundle;
import android.view.View;
import android.widget.ImageView;
import android.widget.TextView;
import android.widget.Toast;

import java.io.InputStream;
import java.util.ArrayList;

public class ShareReceiverActivity extends Activity {

    private TextView sharedTextView;
    private ImageView sharedImageView;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_share_receiver);

        sharedTextView = findViewById(R.id.sharedTextView);
        sharedImageView = findViewById(R.id.sharedImageView);

        handleIntent(getIntent());
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        setIntent(intent); // Update the current intent
        handleIntent(intent);
    }

    private void handleIntent(Intent intent) {
        String action = intent.getAction();
        String type = intent.getType();

        // Hide both views initially
        sharedTextView.setVisibility(View.GONE);
        sharedImageView.setVisibility(View.GONE);

        if (Intent.ACTION_SEND.equals(action) && type != null) {
            if ("text/plain".equals(type)) {
                handleSendText(intent);
            } else if (type.startsWith("image/")) {
                handleSendImage(intent);
            }
        } else if (Intent.ACTION_SEND_MULTIPLE.equals(action) && type != null) {
            if ("text/plain".equals(type)) {
                handleSendMultipleText(intent);
            } else if (type.startsWith("image/")) {
                handleSendMultipleImages(intent);
            }
        } else {
            Toast.makeText(this, "No sharable content found.", Toast.LENGTH_SHORT).show();
        }
    }

    private void handleSendText(Intent intent) {
        String sharedText = intent.getStringExtra(Intent.EXTRA_TEXT);
        if (sharedText != null && !sharedText.isEmpty()) {
            sharedTextView.setText(sharedText);
            sharedTextView.setVisibility(View.VISIBLE);
        } else {
            Toast.makeText(this, "No text content received.", Toast.LENGTH_SHORT).show();
        }
    }

    private void handleSendImage(Intent intent) {
        Uri imageUri = intent.getParcelableExtra(Intent.EXTRA_STREAM);
        if (imageUri != null) {
            try {
                // Request read permission for the URI if needed (implicit for content URIs usually)
                getContentResolver().takePersistableUriPermission(imageUri, Intent.FLAG_GRANT_READ_URI_PERMISSION);
                InputStream inputStream = getContentResolver().openInputStream(imageUri);
                if (inputStream != null) {
                    Bitmap bitmap = BitmapFactory.decodeStream(inputStream);
                    sharedImageView.setImageBitmap(bitmap);
                    sharedImageView.setVisibility(View.VISIBLE);
                    inputStream.close();
                } else {
                    Toast.makeText(this, "Failed to open image stream.", Toast.LENGTH_LONG).show();
                }
            } catch (Exception e) {
                Toast.makeText(this, "Failed to load image: " + e.getMessage(), Toast.LENGTH_LONG).show();
                e.printStackTrace();
            }
        } else {
            Toast.makeText(this, "No image URI received.", Toast.LENGTH_SHORT).show();
        }
    }

    private void handleSendMultipleText(Intent intent) {
        ArrayList<String> sharedTexts = intent.getStringArrayListExtra(Intent.EXTRA_TEXT);
        if (sharedTexts != null && !sharedTexts.isEmpty()) {
            StringBuilder combinedText = new StringBuilder();
            for (String text : sharedTexts) {
                if (text != null && !text.isEmpty()) {
                    combinedText.append(text).append("\n\n");
                }
            }
            if (combinedText.length() > 0) {
                sharedTextView.setText(combinedText.toString().trim());
                sharedTextView.setVisibility(View.VISIBLE);
            } else {
                Toast.makeText(this, "No text content received from multiple shares.", Toast.LENGTH_SHORT).show();
            }
        } else {
            Toast.makeText(this, "No text content received from multiple shares.", Toast.LENGTH_SHORT).show();
        }
    }

    private void handleSendMultipleImages(Intent intent) {
        ArrayList<Uri> imageUris = intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM);
        if (imageUris != null && !imageUris.isEmpty()) {
            // For simplicity, we'll display only the first image.
            // A RecyclerView or multiple ImageViews would be needed for all images.
            Uri firstImageUri = imageUris.get(0);
            try {
                // Request read permission for the URI
                getContentResolver().takePersistableUriPermission(firstImageUri, Intent.FLAG_GRANT_READ_URI_PERMISSION);
                InputStream inputStream = getContentResolver().openInputStream(firstImageUri);
                if (inputStream != null) {
                    Bitmap bitmap = BitmapFactory.decodeStream(inputStream);
                    sharedImageView.setImageBitmap(bitmap);
                    sharedImageView.setVisibility(View.VISIBLE);
                    inputStream.close();
                    if (imageUris.size() > 1) {
                        Toast.makeText(this, "Multiple images received. Displaying the first one.", Toast.LENGTH_LONG).show();
                    }
                } else {
                    Toast.makeText(this, "Failed to open image stream for first image.", Toast.LENGTH_LONG).show();
                }
            } catch (Exception e) {
                Toast.makeText(this, "Failed to load first image: " + e.getMessage(), Toast.LENGTH_LONG).show();
                e.printStackTrace();
            }
        } else {
            Toast.makeText(this, "No image URIs received from multiple shares.", Toast.LENGTH_SHORT).show();
        }
    }
}

